import{_ as i,X as a,Y as t,Z as e,$ as o,a1 as d,a0 as l,H as n}from"./framework-4f44829b.js";const r={},s=e("h1",{id:"网络",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#网络","aria-hidden":"true"},"#"),o(" 网络")],-1),h=e("h3",{id:"tcp为什么要三次握手",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#tcp为什么要三次握手","aria-hidden":"true"},"#"),o(" TCP为什么要三次握手")],-1),p={href:"https://tools.ietf.org/html/rfc793",target:"_blank",rel:"noopener noreferrer"},m=l('<ul><li>通过三次握手才能阻止重复历史连接的初始化；</li><li>通过三次握手才能对通信双方的初始序列号进行初始化；</li></ul><p>序列号在 TCP 连接中有着非常重要的作用，初始序列号作为 TCP 连接的一部分也需要在三次握手期间进行初始化，由于 TCP 连接通信的双方都需要获得初始序列号，所以它们其实需要向对方发送 <code>SYN</code> 控制消息并携带自己期望的初始化序列号 <code>SEQ</code>，对方在收到 <code>SYN</code> 消息之后会通过 <code>ACK</code> 控制消息以及 <code>SEQ+1</code> 来进行确认。</p><figure><img src="https://raw.githubusercontent.com/nocetfy/image/main/img/basic-4-way-handshake.png" alt="basic-4-way-handshake" tabindex="0" loading="lazy"><figcaption>basic-4-way-handshake</figcaption></figure><p>如上图所示，通信双方的两个 <code>TCP A/B</code> 分别向对方发送 <code>SYN</code> 和 <code>ACK</code> 控制消息，等待通信双方都获取到了自己期望的初始化序列号之后就可以开始通信了，由于 TCP 消息头的设计，我们可以将中间的两次通信合成一个，<code>TCP B</code> 可以向 <code>TCP A</code> 同时发送 <code>ACK</code> 和 <code>SYN</code> 控制消息，这也就帮助我们将四次通信减少至三次。</p><p>如果通信双方的通信次数只有两次，那么发送方一旦发出建立连接的请求之后它就没有办法撤回这一次请求，如果在网络状况复杂或者较差的网络中，发送方连续发送多次建立连接的请求，如果 TCP 建立连接只能通信两次，那么接收方只能选择接受或者拒绝发送方发起的请求，它并不清楚这一次请求是不是由于网络拥堵而早早过期的连接。</p><p>所以，TCP 选择使用三次握手来建立连接并在连接引入了 <code>RST</code> 这一控制消息，接收方当收到请求时会将发送方发来的 <code>SEQ+1</code> 发送给对方，这时由发送方来判断当前连接是否是历史连接：</p><ul><li>如果当前连接是历史连接，即 <code>SEQ</code> 过期或者超时，那么发送方就会直接发送 <code>RST</code> 控制消息中止这一次连接；</li><li>如果当前连接不是历史连接，那么发送方就会发送 <code>ACK</code> 控制消息，通信双方就会成功建立连接；</li></ul><p>使用三次握手和 <code>RST</code> 控制消息将是否建立连接的最终控制权交给了发送方，因为只有发送方有足够的上下文来判断当前连接是否是错误的或者过期的，这也是 TCP 使用三次握手建立连接的最主要原因。</p><figure><img src="https://raw.githubusercontent.com/nocetfy/image/main/img/tcp-recovery-from-old-duplicate-syn.png" alt="tcp-recovery-from-old-duplicate-syn" tabindex="0" loading="lazy"><figcaption>tcp-recovery-from-old-duplicate-syn</figcaption></figure><p>TCP 建立连接时通过三次握手可以有效地避免历史错误连接的建立，减少通信双方不必要的资源消耗，三次握手能够帮助通信双方获取初始化序列号，它们能够保证数据包传输的不重不丢，还能保证它们的传输顺序，不会因为网络传输的问题发生混乱，到这里不使用『两次握手』和『四次握手』的原因已经非常清楚了：</p><ul><li>『两次握手』：无法避免历史错误连接的初始化，浪费接收方的资源；</li><li>『四次握手』：TCP 协议的设计可以让我们同时传递 <code>ACK</code> 和 <code>SYN</code> 两个控制信息，减少了通信次数，所以不需要使用更多的通信次数传输相同的信息。</li></ul><hr><h3 id="https为什么是安全的" tabindex="-1"><a class="header-anchor" href="#https为什么是安全的" aria-hidden="true">#</a> HTTPS为什么是安全的</h3><p>​ HTTPS可以理解为 HTTP + SSL/TLS，通过SSL证书来验证服务器的身份，并且在浏览器和服务器之间的通信进行混合加密。TLS在传输加密中使用了混合加密，即同时使用对称加密和非对称加密；理由是非对称加密虽然更安全，但加解密速度和效率很低，而使用对称加密又需要解决密钥交换的问题，所以混合加密是使用非对称加密的方式解决对称加密的密钥交换问题。客户端用随机数产生对称算法使用的“会话密钥”（session key）后再使用公钥进行加密，服务端拿到密文后再用私钥解密，拿到session key作为后续对称加密使用的密钥。</p><p>浏览器验证证书的过程如下：</p><ul><li><p>浏览器从服务器拿到证书（证书内包含：服务器公钥、证书有效期、CA机构信息、数字签名等）</p></li><li><p>通过证书有效期、公钥等信息，再依据证书上给出的hash算法，进行hash得到一个值</p></li><li><p>通过本地预装的CA公钥列表(Windows上可以使用certlm.msc查看本地证书)，使用颁发者的公钥对签名进行解密，得到第二个hash值（也就是digest消息摘要）</p></li><li><p>比对两个hash值，如果值相同，则浏览器从服务器拿到的证书可信赖</p></li></ul><img src="https://raw.githubusercontent.com/nocetfy/image/main/img/image-20230223002949110.png" alt="image-20230223002949110" align="left" style="zoom:50%;"><h3 id="浏览器输入一个链接到返回的全过程" tabindex="-1"><a class="header-anchor" href="#浏览器输入一个链接到返回的全过程" aria-hidden="true">#</a> 浏览器输入一个链接到返回的全过程</h3><blockquote><ol><li>DNS域名解析</li><li>发起TCP连接</li><li>发起HTTP请求</li><li>服务器处理请求并返回响应结果</li><li>浏览器解析渲染页面</li><li>断开连接</li></ol></blockquote>',19);function u(g,f){const c=n("ExternalLinkIcon");return a(),t("div",null,[s,h,e("p",null,[e("a",p,[o("Transmission Control Protocol"),d(c)]),o(" 文档中非常清楚地定义了 TCP 中的连接是什么，我们简单总结一下：用于保证可靠性和流控制机制的信息，包括 Socket、序列号以及窗口大小叫做连接。")]),m])}const _=i(r,[["render",u],["__file","网络.html.vue"]]);export{_ as default};
